module shift_register(
    input  clk,
    input  load,
    input  [3:0] data_in,
    output [3:0] data_out
);

reg [3:0] unused_register;

always @(posedge clk) begin
    if (load) begin
        unused_register <= data_in;
    end else begin
        unused_register <= {1'b0, unused_register[3:1]};
    end
end

assign data_out = unused_register;

endmodule
